const pptxgen = require("pptxgenjs");

// ── Lesson data ────────────────────────────────────────────────────────────
// DO NOT EDIT THIS FILE. Write /home/claude/lesson.json for each lesson.
const LESSON    = JSON.parse(require("fs").readFileSync("/home/claude/lesson.json", "utf8"));
const WORDS     = LESSON.words;
const DEFS      = LESSON.defs;
const SENTENCES = LESSON.sentences;
const SPELL_DATA= LESSON.spellData;
const CLOZE_ORDER = LESSON.clozeOrder;

const pres = new pptxgen();
pres.layout = "LAYOUT_16x9";
pres.title = "Spelling – " + LESSON.rule + " – Worksheet Activities";

const SW = 10, SH = 5.625;
const MARGIN = 0.35;
const CONTENT_Y = 0.95;
const CONTENT_H = SH - CONTENT_Y - 0.18;

const C = {
  BLACK:   "1A1A1A",
  DGREY:   "444444",
  GREY:    "999999",
  LGREY:   "F2F2F2",
  BGREY:   "CCCCCC",
  PURPLE:  "6750A4",
  LPURPLE: "EDE7F6",
  PINK:    "E91E8C",
  GREEN:   "2E7D32",
  WHITE:   "FFFFFF",
  BDR:     "AAAAAA",
  RED:     "C0392B",
};

const FONT = "Aptos";



// ── Helpers ────────────────────────────────────────────────

function addHeader(s, activity, instruction, svLabel) {
  const labelRight = svLabel ? `${activity}  |  ${svLabel}` : activity;
  s.addText(labelRight, {
    x: MARGIN, y: 0.10, w: SW - MARGIN * 2, h: 0.24,
    fontSize: 8.5, fontFace: FONT, color: C.GREY, align: "left"
  });
  s.addText(instruction, {
    x: MARGIN, y: 0.32, w: SW - MARGIN * 2 - 2.2, h: 0.50,
    fontSize: 11.5, fontFace: FONT, color: C.BLACK, bold: true,
    align: "left", valign: "middle"
  });

  // Rule below header
  s.addShape(pres.shapes.RECTANGLE, {
    x: MARGIN, y: 0.84, w: SW - MARGIN * 2, h: 0.020,
    fill: { color: C.BGREY }, line: { color: C.BGREY, width: 0 }
  });
}

function wLines(s, x, y, w, n, spacing) {
  for (let i = 0; i < n; i++) {
    s.addShape(pres.shapes.RECTANGLE, {
      x, y: y + i * spacing, w, h: 0.013,
      fill: { color: C.PURPLE }, line: { color: C.PURPLE, width: 0 }
    });
  }
}

const CW = SW - MARGIN * 2;   // content width = 9.30"

// ═══════════════════════════════════════════════════════════
// SLIDE 1 — Word Sort
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Word Sort",
    "Can you sort this week's words? Some can ONLY be a verb. Others can be a verb OR a noun.",
    `${LESSON.code}.6`);

  // Word chips — 10 chips across the slide
  const chipW = 0.81, chipH = 0.34, chipGap = 0.042;
  const totalChips = WORDS.length * chipW + (WORDS.length - 1) * chipGap;
  const chipX0 = MARGIN + (CW - totalChips) / 2;
  const chipY  = CONTENT_Y + 0.05;

  WORDS.forEach((w, i) => {
    const cx = chipX0 + i * (chipW + chipGap);
    s.addShape(pres.shapes.ROUNDED_RECTANGLE, {
      x: cx, y: chipY, w: chipW, h: chipH,
      rectRadius: 0.07, fill: { color: C.LGREY }, line: { color: C.BGREY, width: 0.8 }
    });
    s.addText(w, {
      x: cx, y: chipY, w: chipW, h: chipH,
      fontSize: 10.5, fontFace: FONT, color: C.BLACK, bold: true,
      align: "center", valign: "middle", margin: 0
    });
  });

  // Two sort boxes
  const boxY  = CONTENT_Y + 0.50;
  const boxH  = SH - boxY - 0.15;
  const boxW  = (CW - 0.30) / 2;

  const boxes = [
    { x: MARGIN,           bdr: "4A3F9F", label: LESSON.wordSort.box1label, sub: LESSON.wordSort.box1sub, lines: 4 },
    { x: MARGIN+boxW+0.30, bdr: C.GREEN,  label: LESSON.wordSort.box2label,      sub: LESSON.wordSort.box2sub, lines: 6 },
  ];

  boxes.forEach(b => {
    s.addShape(pres.shapes.ROUNDED_RECTANGLE, {
      x: b.x, y: boxY, w: boxW, h: boxH,
      rectRadius: 0.10, fill: { color: C.WHITE }, line: { color: b.bdr, width: 2 }
    });
    s.addText(b.label, {
      x: b.x + 0.12, y: boxY + 0.08, w: boxW - 0.24, h: 0.30,
      fontSize: 12.5, fontFace: FONT, bold: true, color: b.bdr, align: "center"
    });
    s.addText(b.sub, {
      x: b.x + 0.12, y: boxY + 0.35, w: boxW - 0.24, h: 0.22,
      fontSize: 9.5, fontFace: FONT, italic: true, color: C.DGREY, align: "center"
    });
    const lStart = boxY + 0.70;
    const lSpace = (boxH - 0.75) / b.lines;
    wLines(s, b.x + 0.22, lStart + lSpace * 0.9, boxW - 0.44, b.lines, lSpace);
  });
}

// ═══════════════════════════════════════════════════════════
// SLIDE 2 — Word Maps (6 words)
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Word Maps",
    "Read each word, break it into syllables, write the sound buttons, then write the word again.",
    `${LESSON.code}.9`);

  // Auto-derive sound buttons from LESSON.phonemes
  const MAP_WORDS = LESSON.wordMaps.words.map(w => ({
    word: w,
    sb: LESSON.phonemes[w].map(p => p.t === "dot" ? p.l + " · " : p.l + " — ").join("").replace(/[· ]+$/, "").trim()
  }));

  const hdr = [
    { text: "Word",            options: { bold: true, fill: { color: C.LPURPLE }, align: "center",  fontSize: 11 } },
    { text: "Syllable Breaks", options: { bold: true, fill: { color: C.LPURPLE }, align: "center",  fontSize: 11 } },
    { text: "Sound Buttons",   options: { bold: true, fill: { color: C.LPURPLE }, align: "center",  fontSize: 11 } },
    { text: "My Word",         options: { bold: true, fill: { color: C.LPURPLE }, align: "center",  fontSize: 11 } },
  ];

  const rows = MAP_WORDS.map(m => [
    { text: m.word, options: { bold: true, fill: { color: C.WHITE }, align: "center", fontSize: 12 } },
    { text: "",     options: { fill: { color: C.WHITE } } },
    { text: "",     options: { fill: { color: C.WHITE } } },
    { text: "",     options: { fill: { color: C.WHITE } } },
  ]);

  s.addTable([hdr, ...rows], {
    x: MARGIN, y: CONTENT_Y + 0.04, w: CW, h: CONTENT_H - 0.08,
    border: { pt: 1, color: C.BDR },
    colW: [1.55, 2.10, 3.40, 2.25],
    fontFace: FONT,
    rowH: [0.36, 0.676, 0.676, 0.676, 0.676, 0.676, 0.676],
  });
}

// ═══════════════════════════════════════════════════════════
// SLIDE 3 — Definitions and In a Sentence
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Definitions and In a Sentence",
    "Read each word and its definition. Then write your own sentence using that word.",
    `${LESSON.code}.11`);

  const hdr = [
    { text: "Word",          options: { bold: true, fill: { color: C.LPURPLE }, align: "center", fontSize: 10 } },
    { text: "Definition",    options: { bold: true, fill: { color: C.LPURPLE }, align: "left",   fontSize: 10 } },
    { text: "In a Sentence", options: { bold: true, fill: { color: C.LPURPLE }, align: "center", fontSize: 10 } },
  ];

  const rows = WORDS.map(w => [
    { text: w,       options: { bold: true, fill: { color: C.WHITE }, align: "center", fontSize: 11 } },
    { text: DEFS[w], options: { color: C.DGREY, fill: { color: C.WHITE }, align: "left", fontSize: 8 } },
    { text: "",      options: { fill: { color: C.WHITE } } },
  ]);

  s.addTable([hdr, ...rows], {
    x: MARGIN, y: CONTENT_Y + 0.04, w: CW, h: CONTENT_H - 0.08,
    border: { pt: 1, color: C.BDR },
    colW: [1.30, 3.45, 4.55],
    fontFace: FONT,
    rowH: [0.35, 0.406, 0.406, 0.406, 0.406, 0.406, 0.406, 0.406, 0.406, 0.406, 0.406],
  });
}

// ═══════════════════════════════════════════════════════════
// SLIDE 4 — Spell Check
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Spell Check", "Circle the correct spelling of each word.", `${LESSON.code}.13`);

  const rows = SPELL_DATA.map(row => row.opts.map(cell => ({
    text: cell,
    options: { align: "center", color: C.BLACK, fill: { color: C.WHITE }, fontSize: 14, fontFace: FONT }
  })));

  s.addTable(rows, {
    x: MARGIN, y: CONTENT_Y + 0.04, w: CW, h: CONTENT_H - 0.08,
    border: { pt: 1, color: C.BDR },
    colW: [3.1, 3.1, 3.1],
    fontFace: FONT,
    rowH: 0.441,
  });
}

// ═══════════════════════════════════════════════════════════
// SLIDE 5 — Cloze
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Cloze",
    "Use the words from the word bank to complete each sentence.",
    `${LESSON.code}.15`);

  const ROW_H = (CONTENT_H - 0.06) / 10;
  const wbW = 1.25;

  // Word bank table
  const wbRows = WORDS.map(w => [{
    text: w,
    options: { align: "center", bold: true, color: C.BLACK, fill: { color: C.WHITE }, fontSize: 10, fontFace: FONT, valign: "middle" }
  }]);
  s.addTable(wbRows, {
    x: MARGIN, y: CONTENT_Y + 0.03, w: wbW, h: CONTENT_H - 0.06,
    border: { pt: 1, color: C.BDR },
    rowH: ROW_H,
  });

  // Sentences
  const BLANK = "____________________________";
  const sentX = MARGIN + wbW + 0.18;
  const sentW = CW - wbW - 0.18;

  CLOZE_ORDER.forEach((w, i) => {
    const sentence = SENTENCES[w];
    const idx = sentence.indexOf(w);
    const before = sentence.substring(0, idx);
    const after  = sentence.substring(idx + w.length);
    s.addText([
      { text: before, options: { color: C.BLACK } },
      { text: BLANK,  options: { color: C.BLACK } },
      { text: after,  options: { color: C.BLACK } },
    ], {
      x: sentX, y: CONTENT_Y + 0.03 + i * ROW_H, w: sentW, h: ROW_H,
      fontSize: 11, fontFace: FONT, valign: "middle",
    });
    // Divider line between rows
    if (i < 9) {
      s.addShape(pres.shapes.RECTANGLE, {
        x: sentX, y: CONTENT_Y + 0.03 + (i + 1) * ROW_H - 0.012, w: sentW, h: 0.010,
        fill: { color: "E8E8E8" }, line: { color: "E8E8E8", width: 0 }
      });
    }
  });
}

// ═══════════════════════════════════════════════════════════
// SLIDE 6 — Morphology Matrix
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Morphology Matrix",
    "How many new words can you make by adding suffix(es) or prefix(es) to the base word?",
    `${LESSON.code}.19`);

  const baseW = 2.90, baseX = MARGIN;
  const baseY = CONTENT_Y + 0.08, baseH = CONTENT_H - 0.12;

  s.addShape(pres.shapes.ROUNDED_RECTANGLE, {
    x: baseX, y: baseY, w: baseW, h: baseH,
    rectRadius: 0.10, fill: { color: C.WHITE }, line: { color: C.GREEN, width: 2 }
  });
  s.addText("Base Word", {
    x: baseX, y: baseY + 0.08, w: baseW, h: 0.30,
    fontSize: 13, fontFace: FONT, bold: true, color: C.GREEN, align: "center"
  });
  s.addText(LESSON.morphMatrix.baseWord, {
    x: baseX, y: baseY + 0.44, w: baseW, h: 1.80,
    fontSize: 58, fontFace: FONT, color: C.BLACK, align: "center", valign: "middle"
  });
  s.addText(LESSON.morphMatrix.def, {
    x: baseX + 0.15, y: baseY + baseH - 0.55, w: baseW - 0.30, h: 0.50,
    fontSize: 9, fontFace: FONT, italic: true, color: C.GREY, align: "center", valign: "middle"
  });

  // Suffix grid — 2 × 3
  const gridX = MARGIN + baseW + 0.35;
  const gridW = SW - gridX - MARGIN;
  const gcw   = (gridW - 0.15) / 2;
  const grh   = (baseH - 0.38 - 0.10) / 3;

  s.addText("Add a suffix or prefix:", {
    x: gridX, y: baseY + 0.04, w: gridW, h: 0.30,
    fontSize: 13, fontFace: FONT, bold: true, color: C.PURPLE, align: "center"
  });

  const suffixes = LESSON.morphMatrix.suffixes;
  suffixes.forEach((sf, i) => {
    const col = i % 2, row = Math.floor(i / 2);
    const cx = gridX + col * (gcw + 0.15);
    const cy = baseY + 0.38 + row * (grh + 0.10);
    s.addShape(pres.shapes.ROUNDED_RECTANGLE, {
      x: cx, y: cy, w: gcw, h: grh,
      rectRadius: 0.08, fill: { color: C.LGREY }, line: { color: C.PURPLE, width: 1.5 }
    });
    s.addText(sf, {
      x: cx, y: cy + 0.06, w: gcw, h: 0.26,
      fontSize: 14, fontFace: FONT, bold: true, color: C.DGREY, align: "center"
    });
    // Writing line
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx + 0.18, y: cy + grh - 0.34, w: gcw - 0.36, h: 0.013,
      fill: { color: C.PURPLE }, line: { color: C.PURPLE, width: 0 }
    });
  });
}

// ═══════════════════════════════════════════════════════════
// SLIDE 7 — Scrambled Syllables
// ═══════════════════════════════════════════════════════════
{
  const s = pres.addSlide();
  addHeader(s, "Scrambled Syllables",
    "These words have been scrambled into their syllables. Can you put them back together?",
    "");

  // Auto-generate scrambled syllables from LESSON.syllableBreaks (all 10 words)
  const SCRAMBLED = LESSON.words.map(w => {
    const syl = (LESSON.syllableBreaks && LESSON.syllableBreaks[w]) || LESSON.wordMaps.syllables[w] || w;
    const parts = syl.split(" | ").reverse();  // reverse order = scrambled
    return { parts };
  });

  const colW2 = (CW - 0.25) / 2;
  const rowH2 = CONTENT_H / 5;

  SCRAMBLED.forEach((item, i) => {
    const col = i % 2, row = Math.floor(i / 2);
    const cx = MARGIN + col * (colW2 + 0.25);
    const cy = CONTENT_Y + 0.02 + row * rowH2;

    // Build coloured separator text
    const runs = item.parts.map((p, pi) => [
      { text: p, options: { color: C.BLACK, fontSize: 16, fontFace: FONT } },
      ...(pi < item.parts.length - 1
        ? [{ text: " | ", options: { color: C.RED, fontSize: 16, fontFace: FONT, bold: true } }]
        : [])
    ]).flat();

    s.addText(runs, {
      x: cx, y: cy + 0.04, w: colW2, h: 0.38,
      align: "left", valign: "middle"
    });
    // Writing line
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: cy + rowH2 - 0.18, w: colW2 * 0.78, h: 0.013,
      fill: { color: C.PURPLE }, line: { color: C.PURPLE, width: 0 }
    });
  });
}

// ─── Write ────────────────────────────────────────────────
pres.writeFile({ fileName: `/home/claude/spelling_worksheets_${LESSON.code}.pptx` })
  .then(() => console.log("Done: spelling_worksheets_" + LESSON.code + ".pptx"))
  .catch(e => console.error(e));
